// TestGradientCellsSingleStopAutoShade verifies linear-gradient(#color) — a single
// explicit stop — spreads into a darker-base-lighter blend sized to cells, instead of
// collapsing like an ordinary invalid (< 2 stop) gradient.
func TestGradientCellsSingleStopAutoShade(t *testing.T) {
	result := GradientCells("linear-gradient(#3465A4)", 5, &Defaults{}, false, nil, nil)
	assert.Len(t, result, 5)

	middle := result[2]
	assert.Equal(t, Ansi("38;2;52;101;164"), middle, "the middle cell should land on the configured color")

	first, last := result[0], result[len(result)-1]
	assert.NotEqual(t, first, middle, "the darker endpoint must differ from the base color")
	assert.NotEqual(t, last, middle, "the lighter endpoint must differ from the base color")
	assert.NotEqual(t, first, last, "the darker and lighter endpoints must differ")
}

// TestGradientCellsSingleStopAutoShadeSingleCell verifies a single-cell segment (too
// narrow to show any blend) renders the configured color unmodified, not a shaded
// endpoint.
func TestGradientCellsSingleStopAutoShadeSingleCell(t *testing.T) {
	result := GradientCells("linear-gradient(#3465A4)", 1, &Defaults{}, false, nil, nil)
	assert.Equal(t, []Ansi{"38;2;52;101;164"}, result)
}

